import{c as t,Q as n,j as a,m as i}from"./chunks/framework.BPKcPtvA.js";const o="/screenshots/getting-started-sidebars-light.png",s="/screenshots/getting-started-sidebars-dark.png",m=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1779094756000}'),r={name:"guide/getting-started.md"};function l(d,e,g,h,c,u){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>This page walks through what to expect the first time you sign in to the Console. It does not cover deployment or configuration of the Console itself — those are internal engineering topics.</p><h2 id="_1-receiving-an-invite" tabindex="-1">1. Receiving an invite <a class="header-anchor" href="#_1-receiving-an-invite" aria-label="Permalink to &quot;1. Receiving an invite&quot;">​</a></h2><p>You cannot self-register for the Console. Every account is created by an existing admin and arrives as an email invite.</p><p>When you receive the invite email, click the link. You will land on the <strong>Accept Invite</strong> page. See <a href="./account/accepting-an-invite">Accepting an Invite</a> for the full step-by-step.</p><h2 id="_2-signing-in" tabindex="-1">2. Signing in <a class="header-anchor" href="#_2-signing-in" aria-label="Permalink to &quot;2. Signing in&quot;">​</a></h2><p>After your account is set up, future sign-ins go through the standard login flow:</p><ol><li>Open the Console URL.</li><li>Enter your email address.</li><li>If your organisation has multiple sign-in methods configured (password, SSO, identity provider), pick one. If only one is configured, you go straight there.</li><li>Authenticate. You will be redirected back to the Console and dropped at your home page.</li></ol><p>The home page depends on who you are:</p><ul><li><strong>Internal operators</strong> land on <code>/dashboard</code> — the platform-wide health overview.</li><li><strong>Customer owners</strong> and <strong>admins</strong> land on their customer&#39;s portal dashboard at <code>/customers/:customerId/dashboard</code>.</li><li><strong>Customer members</strong> without elevated portal access land on their personal account page.</li></ul><p>See <a href="./account/signing-in">Signing In</a> for details, including what to do when sign-in fails.</p><h2 id="_3-finding-your-way-around" tabindex="-1">3. Finding your way around <a class="header-anchor" href="#_3-finding-your-way-around" aria-label="Permalink to &quot;3. Finding your way around&quot;">​</a></h2><p>The left-hand sidebar is your map.</p><p>In the <strong>Admin Console</strong>, sections are grouped by domain — Customers, Tenants, Instances, Migrations, Releases, Finance, System, and so on. Each row in the sidebar opens a list page; clicking a row in that list opens a detail page.</p><p>In the <strong>Customer Portal</strong>, the sidebar is shorter and scoped to a single customer: Dashboard, Workspace (Tenants, Instances, Users), Billing, What&#39;s New, Settings, and Account.</p><p>If you belong to more than one customer, a switcher near the top of the portal lets you change customers without signing out.</p><p><img src="'+o+'" alt="Admin and portal sidebars" class="light-only"><img src="'+s+'" alt="Admin and portal sidebars" class="dark-only"></p><h2 id="_4-doing-your-first-task" tabindex="-1">4. Doing your first task <a class="header-anchor" href="#_4-doing-your-first-task" aria-label="Permalink to &quot;4. Doing your first task&quot;">​</a></h2><p>Pick whichever applies:</p><ul><li><strong>Onboarding a new customer?</strong> Open Customers → New Customer. See <a href="./admin/customers">Customers</a>.</li><li><strong>Provisioning a tenant?</strong> Open Tenants → New Tenant. See <a href="./admin/tenants">Tenants</a>.</li><li><strong>Inviting users to a customer?</strong> Open the customer&#39;s detail page → Users tab → Invite Users. See <a href="./admin/customers#users-tab">Customers</a>.</li><li><strong>Cutting a release?</strong> Open Releases → New Release. See <a href="./admin/releases">Releases</a>.</li><li><strong>Reviewing billing?</strong> Open Finance → Customers. See <a href="./admin/finance/customers">Finance Customers</a>.</li></ul><h2 id="_5-when-things-go-wrong" tabindex="-1">5. When things go wrong <a class="header-anchor" href="#_5-when-things-go-wrong" aria-label="Permalink to &quot;5. When things go wrong&quot;">​</a></h2><ul><li>The action button is greyed out → your role probably does not have permission. Check <a href="./concepts/roles-and-permissions">Roles &amp; Permissions</a>.</li><li>A status banner appears on a tenant or instance → see <a href="./concepts/statuses">Lifecycle Statuses</a>.</li><li>Something failed and you need to see what happened → check the <a href="./admin/audit-log">Audit Log</a> for record-level events, or the <a href="./admin/email-logs">Email Logs</a> for delivery issues.</li></ul><p>If you are an operator and the failure looks systemic, see the engineering team&#39;s internal runbooks. They are not part of this user guide.</p>',23)])])}const f=t(r,[["render",l]]);export{m as __pageData,f as default};
